import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.CKCxdkvf.js";const d=JSON.parse('{"title":"PRD-001 — Solar System Explorer","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-001.md","filePath":"prd/PRD-001.md"}'),o={name:"prd/PRD-001.md"};function r(n,e,l,h,c,p){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="prd-001-—-solar-system-explorer" tabindex="-1">PRD-001 — Solar System Explorer <a class="header-anchor" href="#prd-001-—-solar-system-explorer" aria-label="Permalink to &quot;PRD-001 — Solar System Explorer&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Sources · 01_Orrery_Vision.md §solar-system · 02_Project_Concept.md §six-screens Audiences · curious learner, STEM student (PA §audiences) Promises · real physics, educational at every level (PA §promises) Principles · physics first, prototype is ground truth (PA §principles) Why this is a PRD · This screen changes how a person understands the solar system — not just what the planets look like, but how they actually move and why the geometry makes Mars missions hard. It is the educational core of Orrery.</p></blockquote><p>A person who has watched a spacecraft launch but never understood why it took seven months is sitting at home with a browser open. They click EXPLORE. The solar system rotates in front of them. They click Earth. A panel slides in. They switch to the TECHNICAL tab. For the first time they watch a number — orbital velocity in km/s — change as Earth moves along its ellipse. The number is bigger near perihelion. It makes sense.</p><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>The geometry of the solar system is almost never shown correctly. Diagrams show circular orbits. Animations show equal-speed planets. The 26-month Mars launch window looks arbitrary. The reason Mars missions take 259 days is invisible — there is no tool that shows the actual elliptical transfer orbit in context, with the actual orbital velocities changing in real time.</p><p>Orrery&#39;s solar system explorer is that tool.</p><h2 id="the-experience" tabindex="-1">The experience <a class="header-anchor" href="#the-experience" aria-label="Permalink to &quot;The experience&quot;">​</a></h2><p>The default view is 3D. The eight planets orbit the Sun at their correct relative speeds. Inclinations are visible — the Kuiper Belt objects tilt noticeably out of the ecliptic plane. Saturn&#39;s rings are there. The Sun is clickable.</p><p>The user clicks on Mars. The detail panel opens to OVERVIEW: the editorial description of Mars, its key parameters, what makes it interesting. They switch to TECHNICAL: eccentricity 0.093, inclination 1.85°, orbital velocity updating in real time from the vis-viva equation. They watch the velocity increase as Mars moves toward perihelion. They switch to SIZES: a canvas showing all eight planets at true relative scale. Jupiter is enormous. Earth is a dot.</p><p>They switch to 2D. The solar system flattens to a top-down view. They can see the orbital ellipses — Earth&#39;s is nearly circular; Mars&#39;s is noticeably eccentric. They zoom out with the scroll wheel and see the Kuiper Belt and Planet Nine&#39;s hypothetical orbit at the edge.</p><p>They click the Sun. The panel opens. The editorial text explains that the Sun contains 99.86% of all mass in the solar system, that it fuses 600 million tonnes of hydrogen per second, that in 5 billion years it will engulf the inner planets. The LEARN tab links to the Milky Way article — because the Sun is also our position in the galaxy, and that context matters.</p><h2 id="why-now" tabindex="-1">Why now <a class="header-anchor" href="#why-now" aria-label="Permalink to &quot;Why now&quot;">​</a></h2><p>The solar system explorer is Act 1 of Orrery&#39;s narrative. Without it, the mission configurator has no context — the user doesn&#39;t understand why launch windows exist or why the trajectory matters. It is the foundation everything else builds on.</p><h2 id="success-looks-like" tabindex="-1">Success looks like <a class="header-anchor" href="#success-looks-like" aria-label="Permalink to &quot;Success looks like&quot;">​</a></h2><p>A user with no physics background can correctly explain why Mars missions can only launch every 26 months after using this screen for 10 minutes.</p><p>A STEM student uses the TECHNICAL tab to verify that the vis-viva velocity they computed in class matches what Orrery shows for their planet.</p><p>A user zooms out in 2D until they can see Planet Nine&#39;s hypothetical orbit and reads the label with genuine curiosity.</p><p>The Sun panel is the first place a general user has ever been shown their position in the Milky Way in context of a solar system view.</p><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li>Moons of other planets (only Earth&#39;s Moon and Saturn&#39;s rings are shown)</li><li>Asteroid belt individual objects (only the belt density cloud is shown)</li><li>N-body gravitational effects</li><li>Atmospheric detail on planet spheres</li></ul><h2 id="the-sharpest-threat" tabindex="-1">The sharpest threat <a class="header-anchor" href="#the-sharpest-threat" aria-label="Permalink to &quot;The sharpest threat&quot;">​</a></h2><p>The TECHNICAL tab shows real numbers. If a curious learner uses it and the numbers feel arbitrary — if the vis-viva velocity is just a number with no intuition attached — the tab fails. The numbers need to be explained in context. &quot;This is why Mars is faster near the Sun&quot; is the experience; the number alone is not.</p><h2 id="open-threads" tabindex="-1">Open threads <a class="header-anchor" href="#open-threads" aria-label="Permalink to &quot;Open threads&quot;">​</a></h2><ul><li>UXS-001 for full visual contract</li><li>ADR-001, ADR-011, ADR-012 lock the rendering, language, and framework decisions</li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Prototype: <code>docs/prototypes/P01_solar-system-explorer.html</code></li><li>Concept: <code>docs/concept/02_Project_Concept.md §six-screens</code></li></ul>',26)])])}const y=t(o,[["render",r]]);export{d as __pageData,y as default};
